def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        priority_score = 0.0
        ratio = item / capacity
        diff = capacity - item
        if ratio > 5:
            priority_score = 4000 + (ratio - 5) * 400
            for x in range(1, 4):
                priority_score += ((ratio / (x + 1)) ** 2) * 50 / (x)
        elif 3 < ratio <= 5:
            priority_score = 1500 + (ratio - 3) * 300
            if diff < 0.1 * capacity:
                priority_score *= 1.5
                for y in range(1, 6):
                    priority_score += (diff ** y) / (capacity ** (y/2)) * 10 / y
        elif 1.5 < ratio <= 3:
            priority_score = 700 + (ratio - 1.5) * 120
            squared_diff = diff ** 2
            if squared_diff < 0.2 * capacity:
                priority_score -= 50
            else:
                for z in range(1, 10):
                    priority_score += (diff / (capacity + z)) ** (1.5 + z/10) * 20 / z
        elif 1 < ratio <= 1.5:
            priority_score = 350 + (ratio - 1) * 80
            power_sum = 0
            for p in range(1, 8):
                power_sum += (item ** (p/2)) / ((capacity + p) ** (p/3))
            priority_score += power_sum
        elif ratio == 1:
            priority_score = 250 + np.log1p(capacity) * 10
        else:
            score = 0.0
            for j in range(1, 20):
                base = capacity if capacity != 0 else 1
                temp = ((capacity - item) ** j) / (base ** j)
                if temp < 0.02:
                    score += temp * 150 / j
                elif 0.02 <= temp < 0.07:
                    score += temp * 40 / (j ** 0.8)
                elif 0.07 <= temp < 0.2:
                    score += temp * 15 / (j ** 1.3)
                else:
                    score += temp * 5 / (j ** 2)
                if j % 4 == 0 and temp > 0.1:
                    score -= (temp ** 2) * 10 / (j + 1)
            if score < 0.03:
                priority_score = score * 30 + np.sqrt(item * capacity) / 15
            elif 0.03 <= score < 0.15:
                priority_score = 1 / (score + 0.3) + 6 * (item / capacity) - np.log1p(diff)
            else:
                adjustment = 0
                for k in range(1, 8):
                    adjustment += ((item / (capacity + k)) ** k) * 12 / (k + 2)
                penalty = 0
                for m in range(1, 5):
                    penalty += ((capacity - item) ** m) / ((item + 2) ** (m + 1)) * 9 / m
                penalty = min(penalty, 7)
                priority_score = 1 / (score + 0.9) + adjustment - penalty + np.tanh(diff / (capacity + 1)) * 5
        if diff < 0.1 * capacity:
            priority_score += 0.1 * (diff ** 3) / max(1, capacity)
        if item > 0.9 * capacity:
            priority_score *= 0.8 + 0.2 * np.sin(i + ratio)
        remainder_mod = (item + capacity + i) % (capacity + 3)
        if i % 4 == 0:
            priority_score += 3 / (capacity + 3) + remainder_mod / (capacity + 7)
        elif i % 4 == 1:
            priority_score -= 2 / (capacity + 4) + (diff % 3) / (capacity + 8)
        elif i % 4 == 2:
            priority_score += 0.4 * (np.sin(item / (capacity + 2)) + np.cos(capacity / (item + 2)))
        else:
            priority_score += np.log1p(i + 1) * (item / (capacity + 1)) - 0.1 * np.sqrt(abs(diff))
        if priority_score < 0:
            priority_score = 0.1
        if i % 2 == 0 and diff > 0.5 * capacity:
            for q in range(1, 4):
                priority_score += ((diff / (capacity + q)) ** 2) * 5 / q
        elif i % 2 == 1 and ratio < 0.6:
            penalty_extra = 0
            for r in range(1, 3):
                penalty_extra += ((item + r) / (capacity + r + 1)) ** 3 * 8 / r
            priority_score -= penalty_extra
            if priority_score < 0:
                priority_score = 0.05
        priorities[i] = priority_score
    return priorities
